m365-022.implementationNotes:
# Connect to Exchange Online
Connect-ExchangeOnline

# Find transport rules that forward externally
Get-TransportRule | Where-Object {
  $_.RedirectMessageTo -or $_.BlindCopyTo -or $_.CopyTo
} | Select-Object Name, State, Priority, RedirectMessageTo, BlindCopyTo | Format-List

# Find user-level inbox rules forwarding externally
$mailboxes = Get-EXOMailbox -ResultSize Unlimited -PropertySets Minimum
foreach ($mbx in $mailboxes) {
  $rules = Get-InboxRule -Mailbox $mbx.UserPrincipalName -ErrorAction SilentlyContinue
  $fwd = $rules | Where-Object { $_.ForwardTo -or $_.ForwardAsAttachmentTo -or $_.RedirectTo }
  if ($fwd) {
    Write-Warning "$($mbx.UserPrincipalName) has forwarding rules:"
    $fwd | Select-Object Name, ForwardTo, RedirectTo | Format-Table
  }
}

# Block auto-forwarding to external domains
New-TransportRule -Name 'Block External Auto-Forward' \
  -FromScope InOrganization \
  -SentToScope NotInOrganization \
  -MessageTypeMatches AutoForward \
  -RejectMessageReasonText 'External mail forwarding is blocked per security policy'
